727	/* This is a debugging function that gets called when we detect something
728	 * wrong with the replication protocol: the goal is to peek into the
729	 * replication backlog and show a few final bytes to make simpler to
730	 * guess what kind of bug it could be. */
731	void showLatestBacklog(void) {
732	    if (server.repl_backlog == NULL) return;
733	    if (listLength(server.repl_buffer_blocks) == 0) return;
734	    if (server.hide_user_data_from_log) {
735	        serverLog(LL_NOTICE,"hide-user-data-from-log is on, skip logging backlog content to avoid spilling PII.");
736	        return;
737	    }
738	
739	    size_t dumplen = 256;
740	    if (server.repl_backlog->histlen < (long long)dumplen)
741	        dumplen = server.repl_backlog->histlen;
742	
743	    sds dump = sdsempty();
744	    listNode *node = listLast(server.repl_buffer_blocks);
745	    while(dumplen) {
746	        if (node == NULL) break;
747	        replBufBlock *o = listNodeValue(node);
748	        size_t thislen = o->used >= dumplen ? dumplen : o->used;
749	        sds head = sdscatrepr(sdsempty(), o->buf+o->used-thislen, thislen);
750	        sds tmp = sdscatsds(head, dump);
751	        sdsfree(dump);
752	        dump = tmp;
753	        dumplen -= thislen;
754	        node = listPrevNode(node);
755	    }
756	
757	    /* Finally log such bytes: this is vital debugging info to
758	     * understand what happened. */
759	    serverLog(LL_NOTICE,"Latest backlog is: '%s'", dump);
760	    sdsfree(dump);
761	}
