483	/* Allocate a new replication backlog block. Called when current block is full. */
484	static void replBufWriterAllocBlock(replBufWriter *wr, size_t hint) {
485	    static long long repl_block_id = 0;
486	    size_t usable_size;
487	    /* Avoid creating nodes smaller than PROTO_REPLY_CHUNK_BYTES, so that we can append more data into them,
488	     * and also avoid creating nodes bigger than repl_backlog_size / 16, so that we won't have huge nodes that can't
489	     * trim when we only still need to hold a small portion from them. */
490	    size_t limit = max((size_t)server.repl_backlog_size / 16, (size_t)PROTO_REPLY_CHUNK_BYTES);
491	    size_t bsize = min(max(hint, (size_t)PROTO_REPLY_CHUNK_BYTES), limit);
492	    replBufBlock *tail = zmalloc_usable(bsize + sizeof(replBufBlock), &usable_size);
493	    /* Take over the allocation's internal fragmentation */
494	    tail->size = usable_size - sizeof(replBufBlock);
495	    tail->used = 0;
496	    tail->refcount = 0;
497	    tail->repl_offset = server.master_repl_offset + wr->total_len + 1;
498	    tail->id = repl_block_id++;
499	    listAddNodeTail(server.repl_buffer_blocks, tail);
500	    server.repl_buffer_mem += (usable_size + sizeof(listNode));
501	    createReplicationBacklogIndex(listLast(server.repl_buffer_blocks));
502	
503	    /* Update stream state. */
504	    wr->tail = tail;
505	    wr->new_blocks++;
506	    if (wr->start_node == NULL) {
507	        wr->start_node = listLast(server.repl_buffer_blocks);
508	        wr->start_pos = 0;
509	    }
510	}
