379	/* Generally, we only have one replication buffer block to trim when replication
380	 * backlog size exceeds our setting and no replica reference it. But if replica
381	 * clients disconnect, we need to free many replication buffer blocks that are
382	 * referenced. It would cost much time if there are a lots blocks to free, that
383	 * will freeze server, so we trim replication backlog incrementally. */
384	void incrementalTrimReplicationBacklog(size_t max_blocks) {
385	    serverAssert(server.repl_backlog != NULL);
386	
387	    size_t trimmed_blocks = 0;
388	    while (server.repl_backlog->histlen > server.repl_backlog_size &&
389	           trimmed_blocks < max_blocks)
390	    {
391	        /* We never trim backlog to less than one block. */
392	        if (listLength(server.repl_buffer_blocks) <= 1) break;
393	
394	        /* Replicas increment the refcount of the first replication buffer block
395	         * they refer to, in that case, we don't trim the backlog even if
396	         * backlog_histlen exceeds backlog_size. This implicitly makes backlog
397	         * bigger than our setting, but makes the master accept partial resync as
398	         * much as possible. So that backlog must be the last reference of
399	         * replication buffer blocks. */
400	        listNode *first = listFirst(server.repl_buffer_blocks);
401	        serverAssert(first == server.repl_backlog->ref_repl_buf_node);
402	        replBufBlock *fo = listNodeValue(first);
403	        if (fo->refcount != 1) break;
404	
405	        /* We don't try trim backlog if backlog valid size will be lessen than
406	         * setting backlog size once we release the first repl buffer block. */
407	        if (server.repl_backlog->histlen - (long long)fo->size <=
408	            server.repl_backlog_size) break;
409	
410	        /* Decr refcount and release the first block later. */
411	        fo->refcount--;
412	        trimmed_blocks++;
413	        server.repl_backlog->histlen -= fo->size;
414	
415	        /* Go to use next replication buffer block node. */
416	        listNode *next = listNextNode(first);
417	        server.repl_backlog->ref_repl_buf_node = next;
418	        serverAssert(server.repl_backlog->ref_repl_buf_node != NULL);
419	        /* Incr reference count to keep the new head node. */
420	        ((replBufBlock *)listNodeValue(next))->refcount++;
421	
422	        /* Remove the node in recorded blocks. */
423	        uint64_t encoded_offset = htonu64(fo->repl_offset);
424	        raxRemove(server.repl_backlog->blocks_index,
425	            (unsigned char*)&encoded_offset, sizeof(uint64_t), NULL);
426	
427	        /* Delete the first node from global replication buffer. */
428	        serverAssert(fo->refcount == 0 && fo->used == fo->size);

