  static void replBufWriterBegin(replBufWriter *wr) {
      listNode *ln = listLast(server.repl_buffer_blocks);
      replBufBlock *tail = ln ? listNodeValue(ln) : NULL;

      if (tail && tail->used < tail->size) {
          wr->start_node = ln;
          wr->start_pos = tail->used;  // Start from current position
      } else {
          wr->start_node = NULL;
          wr->start_pos = 0;
      }

      wr->total_len = 0;
      wr->new_blocks = 0;
      wr->tail = tail;
  }
  ```

##### **4.3.2 Append: `replBufWriterAppend()` (Fast Path)**
- **File:** `/home/bench/repos/redis/src/replication.c:533-542`
  ```c
  static inline void replBufWriterAppend(replBufWriter *wr, 
                                         const char *buf, size_t len) {
      size_t avail = wr->tail ? wr->tail->size - wr->tail->used : 0;

      // Fast path: fits in current block
      if (len > 0 && avail >= len) {
          memcpy(wr->tail->buf + wr->tail->used, buf, len);
          wr->tail->used += len;
          wr->total_len += len;
          return;
      }

      // Slow path: need to allocate new blocks
      replBufWriterAppendSlow(wr, buf, len);
  }
  ```

##### **4.3.3 Slow Path: `replBufWriterAppendSlow()` with New Block Allocation**
- **File:** `/home/bench/repos/redis/src/replication.c:513-528`
  ```c
  static void replBufWriterAppendSlow(replBufWriter *wr, 
                                      const char *buf, size_t len) {
      while (len > 0) {
          size_t avail = wr->tail ? wr->tail->size - wr->tail->used : 0;
          if (avail > 0) {
              size_t copy = (avail >= len) ? len : avail;
              memcpy(wr->tail->buf + wr->tail->used, buf, copy);
              wr->tail->used += copy;
              wr->total_len += copy;
              buf += copy;
              len -= copy;
          }

          if (len > 0)
              replBufWriterAllocBlock(wr, len);  // Allocate new block
      }
  }
  ```

##### **4.3.4 Allocate: `replBufWriterAllocBlock()`**
- **File:** `/home/bench/repos/redis/src/replication.c:484-510`
  ```c
  static void replBufWriterAllocBlock(replBufWriter *wr, size_t hint) {
      // Allocate between PROTO_REPLY_CHUNK_BYTES and repl_backlog_size/16
      size_t limit = max(server.repl_backlog_size / 16, PROTO_REPLY_CHUNK_BYTES);
      size_t bsize = min(max(hint, PROTO_REPLY_CHUNK_BYTES), limit);

      replBufBlock *tail = zmalloc_usable(bsize + sizeof(replBufBlock), 
                                          &usable_size);
      tail->size = usable_size - sizeof(replBufBlock);
      tail->used = 0;
      tail->refcount = 0;
      tail->repl_offset = server.master_repl_offset + wr->total_len + 1;
      tail->id = repl_block_id++;

      // Add to global replication buffer blocks list
      listAddNodeTail(server.repl_buffer_blocks, tail);
      server.repl_buffer_mem += (usable_size + sizeof(listNode));
      createReplicationBacklogIndex(listLast(server.repl_buffer_blocks));

      wr->tail = tail;
      wr->new_blocks++;
      if (wr->start_node == NULL) {
          wr->start_node = listLast(server.repl_buffer_blocks);
          wr->start_pos = 0;
      }
  }
